import jwt
import json
from typing import Dict, Any, Optional

def decode_and_verify_jwt(token: str, secret: str, algorithm: str = 'HS256') -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): The JWT token to decode
        secret (str): The secret key used to verify the token
        algorithm (str): The algorithm used for verification (default: HS256)
    
    Returns:
        dict: Decoded token contents including header, payload, and verification status
    
    Raises:
        jwt.InvalidTokenError: If the token is invalid or verification fails
        Exception: For any other errors during decoding
    """
    try:
        # Decode the token without verification first to get header
        decoded_header = jwt.get_unverified_header(token)
        
        # Verify and decode the token
        decoded_payload = jwt.decode(token, secret, algorithms=[algorithm])
        
        return {
            'header': decoded_header,
            'payload': decoded_payload,
            'valid': True,
            'error': None
        }
        
    except jwt.InvalidTokenError as e:
        return {
            'header': None,
            'payload': None,
            'valid': False,
            'error': str(e)
        }
    except Exception as e:
        return {
            'header': None,
            'payload': None,
            'valid': False,
            'error': f"Unexpected error: {str(e)}"
        }

def print_jwt_debug_info(token: str, secret: str, algorithm: str = 'HS256') -> None:
    """
    Print formatted debug information about a JWT token
    
    Args:
        token (str): The JWT token to debug
        secret (str): The secret key used to verify the token
        algorithm (str): The algorithm used for verification (default: HS256)
    """
    result = decode_and_verify_jwt(token, secret, algorithm)
    
    print("=== JWT DEBUG INFORMATION ===")
    print(f"Token: {token[:50]}{'...' if len(token) > 50 else ''}")
    print(f"Valid: {result['valid']}")
    
    if result['error']:
        print(f"Error: {result['error']}")
    
    if result['header']:
        print("\n--- Header ---")
        print(json.dumps(result['header'], indent=2))
    
    if result['payload']:
        print("\n--- Payload ---")
        print(json.dumps(result['payload'], indent=2))

